let element, dotNetRef, timeoutMs, timerId, isIdle;
const events = ["mousemove", "keydown", "click", "scroll", "touchstart"];

function onActivity() {
    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync("OnActiveCallback");
    }
    clearTimeout(timerId);
    timerId = setTimeout(onTimeout, timeoutMs);
}

function onTimeout() {
    isIdle = true;
    dotNetRef.invokeMethodAsync("OnIdleCallback");
}

export function init(el, ref, timeout) {
    element = el;
    dotNetRef = ref;
    timeoutMs = timeout;
    isIdle = false;
    events.forEach(e => element.addEventListener(e, onActivity, { passive: true }));
    timerId = setTimeout(onTimeout, timeoutMs);
}

export function dispose() {
    clearTimeout(timerId);
    events.forEach(e => element.removeEventListener(e, onActivity));
}

